# agents/kill_switches.py
from __future__ import annotations
import json, time
from dataclasses import dataclass, field
from typing import Optional
import redis

KILL_SWITCH_KEY = "agent_kill_switches"
TTL_SECONDS = 10  # agents re-read every 10s; cache locally for that window

@dataclass
class AgentKillSwitchState:
    global_enabled: bool = True
    agents: dict[str, bool] = field(default_factory=dict)
    tools: dict[str, bool] = field(default_factory=dict)

    def agent_enabled(self, agent_id: str) -> bool:
        return self.agents.get(agent_id, True)  # default: enabled

    def tool_enabled(self, tool_name: str) -> bool:
        return self.tools.get(tool_name, True)   # default: enabled

    def is_behavior_allowed(self, agent_id: str, tool_name: str) -> bool:
        if not self.global_enabled:
            return False
        if not self.agent_enabled(agent_id):
            return False
        if not self.tool_enabled(tool_name):
            return False
        return True


class KillSwitchStore:
    def __init__(self, redis_url: str) -> None:
        self._r = redis.from_url(redis_url)
        self._cached: Optional[AgentKillSwitchState] = None
        self._cached_at: float = 0.0

    def get(self) -> AgentKillSwitchState:
        now = time.monotonic()
        if self._cached is not None and (now - self._cached_at) < TTL_SECONDS:
            return self._cached

        raw = self._r.get(KILL_SWITCH_KEY)
        if raw is None:
            state = AgentKillSwitchState()  # all enabled by default
        else:
            data = json.loads(raw)
            state = AgentKillSwitchState(
                global_enabled=data.get("global_enabled", True),
                agents=data.get("agents", {}),
                tools=data.get("tools", {}),
            )
        self._cached = state
        self._cached_at = now
        return state

# agents/tool_executor.py
from typing import Any, Callable
from agents.kill_switches import KillSwitchStore

class ToolDisabledError(RuntimeError):
    """Raised when a kill switch is active. Agents must handle this gracefully."""
    def __init__(self, agent_id: str, tool_name: str, reason: str) -> None:
        self.agent_id = agent_id
        self.tool_name = tool_name
        super().__init__(f"[{agent_id}] Tool '{tool_name}' is disabled: {reason}")


class ToolExecutor:
    def __init__(self, ks_store: KillSwitchStore, agent_id: str) -> None:
        self._ks = ks_store
        self._agent_id = agent_id

    def execute(self, tool_name: str, fn: Callable[..., Any], **kwargs: Any) -> Any:
        ks = self._ks.get()

        if not ks.global_enabled:
            raise ToolDisabledError(self._agent_id, tool_name,
                "global AI agent kill switch is active")

        if not ks.agent_enabled(self._agent_id):
            raise ToolDisabledError(self._agent_id, tool_name,
                f"agent '{self._agent_id}' is disabled")

        if not ks.tool_enabled(tool_name):
            raise ToolDisabledError(self._agent_id, tool_name,
                f"tool '{tool_name}' is disabled")

        return fn(**kwargs)


# Usage inside an agent:
class EmailAgent:
    def __init__(self, executor: ToolExecutor) -> None:
        self._exec = executor

    async def run(self, prompt: str) -> str:
        # ... LLM produces tool calls ...
        try:
            result = self._exec.execute("send_email", self._send_email_impl,
                to=recipient, subject=subject, body=body)
        except ToolDisabledError as e:
            # Graceful degradation: notify caller, do not crash
            return f"Action unavailable: {e}"
        return f"Email sent to {recipient}"

# Pattern: graceful skip for non-essential side-effect tools
async def run_with_optional_cache(self, query: str) -> AgentResult:
    answer = await self._llm.complete(query)

    # Cache is optional — skip gracefully if disabled
    try:
        self._exec.execute("cache_result", self._cache_impl,
            key=query, value=answer)
    except ToolDisabledError:
        pass  # cache miss is acceptable; do not surface to caller

    return AgentResult(answer=answer, cached=False)

