"""
Checks that no agent module calls a known side-effectful function
without routing through ToolExecutor. Run in CI as:
  python3 scripts/lint_tool_calls.py agents/
"""
import ast, sys
from pathlib import Path

# Functions that must only be called via ToolExecutor.execute()
GUARDED_FUNCTIONS = {
    "send_email", "send_bulk_email",
    "write_db", "delete_record",
    "post_webhook", "call_external_api",
    "publish_event",
}

class DirectCallDetector(ast.NodeVisitor):
    def __init__(self, filepath: str) -> None:
        self.filepath = filepath
        self.violations: list[tuple[int, str]] = []

    def visit_Call(self, node: ast.Call) -> None:
        name = None
        if isinstance(node.func, ast.Name):
            name = node.func.id
        elif isinstance(node.func, ast.Attribute):
            name = node.func.attr

        if name in GUARDED_FUNCTIONS:
            self.violations.append((node.lineno, name))
        self.generic_visit(node)

def check_file(path: Path) -> list[str]:
    tree = ast.parse(path.read_text())
    detector = DirectCallDetector(str(path))
    detector.visit(tree)
    return [
        f"{path}:{line}: Direct call to '{fn}' — use ToolExecutor.execute()"
        for line, fn in detector.violations
    ]

if __name__ == "__main__":
    agent_dir = Path(sys.argv[1] if len(sys.argv) > 1 else "agents")
    all_violations = []
    for py_file in agent_dir.rglob("*.py"):
        if "test_" in py_file.name or "kill_switch" in py_file.name:
            continue
        all_violations.extend(check_file(py_file))

    if all_violations:
        print("KILL SWITCH LINTER VIOLATIONS:")
        for v in all_violations:
            print(f"  {v}")
        sys.exit(1)
    else:
        print(f"Kill switch lint passed ({len(list(agent_dir.rglob('*.py')))} files checked)")
